+    fn test_search_engine_prefix_matching() {
+        let engine = SearchEngine::open_memory().unwrap();
+        let mut writer = engine.writer(15_000_000).unwrap();
+
+        let tweets = vec![create_test_tweet("1", "Hello world example")];
